#include <stdio.h>
#include <stdlib.h>

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int main() {
    int N, M;
    scanf("%d %d", &N, &M);
    int A[N], B[M];
    for (int i = 0; i < N; i++) {
        scanf("%d", &A[i]);
    }
    for (int i = 0; i < M; i++) {
        scanf("%d", &B[i]);
    }
    qsort(A, N, sizeof(int), compare);
    qsort(B, M, sizeof(int), compare);
    for (int i = 0; i < N; i++) {
        printf("%d %d\n", i, 0);
    }
    for (int i = 1; i < M; i++) {
        printf("0 %d\n", i);
    }
    return 0;
}

